const PROCESSING_FEE = 5;

type Item = { type: string };
type Step = { op: string; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

export const runScenario = (scenario: unknown): unknown => {
  const { steps } = scenario as Scenario;
  const results = steps.map((step) => {
    let base = 0;
    for (const item of step.items) {
      if (item.type === "sword") base += 100;
    }
    const firstInsurance = base * 0.1;
    return { premium: base + firstInsurance + PROCESSING_FEE };
  });
  return { results };
};
